  if (projectsStore.some(project => project.name === name)) {
    throw new Error('DUPLICATE_PROJECT', 'Project with this name already exists');
  }
  const projectId = randomUUID();
  const project = { id: projectId, name };
  projectsStore.push(project);
  return project;
};

const getAllProjects = async () => {
  return projectsStore;
};

const getProjectById = async (projectId) => {
  return projectsStore.find(project => project.id === projectId);
};

