      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('../../lib/id');

let tasksStore = [];

const createTask = async (projectId, title) => {
  const taskId = randomUUID();
  const task = { id: taskId, projectId, title, status: 'todo' };
  tasksStore.push(task);
  return task;
};

const getAllTasks = async (projectId) => {
  return tasksStore.filter(task => task.projectId === projectId);
};

const updateTaskStatus = async (taskId, status) => {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
};

module.exports = { createTask, getAllTasks, updateTaskStatus };
