      "path": "tests/oracle.test.js",
      "content": "const request = require('supertest');
const app = require('../src/app');

let projectId;
let taskId;

describe('Project Management API', () => {
  it('should return health check', async () => {
    const response = await request(app).get('/health');
    expect(response.status).toBe(200);
    expect(response.body).toEqual({ ok: true });
  });

  describe('Projects', () => {
    it('should create a project', async () => {
      const response = await request(app)
        .post('/projects')
        .send({ name: 'Test Project' });
      expect(response.status).toBe(201);
      projectId = response.body.project.id;
    });

    it('should get all projects', async () => {
      const response = await request(app).get('/projects');
      expect(response.status).toBe(200);
      expect(response.body.projects.length).toBeGreaterThan(0);
    });

    it('should get a project by id', async () => {
      const response = await request(app).get(`/projects/${projectId}`);
      expect(response.status).toBe(200);
      expect(response.body.project.id).toBe(projectId);
    });
  });

  describe('Tasks', () => {
    it('should create a task', async () => {
      const response = await request(app)
        .post(`/projects/${projectId}/tasks`)
        .send({ title: 'Test Task' });
      expect(response.status).toBe(201);
      taskId = response.body.task.id;
    });

    it('should get all tasks', async () => {
      const response = await request(app).get(`/projects/${projectId}/tasks`);
      expect(response.status).toBe(200);
      expect(response.body.tasks.length).toBeGreaterThan(0);
    });

    it('should update task status to done', async () => {
      const response = await request(app)
        .patch(`/projects/${projectId}/tasks/${taskId}`)
        .send({ status: 'done' });
      expect(response.status).toBe(200);
      expect(response.body.task.status).toBe('done');
    });
  });

  describe('Comments', () => {
    it('should create a comment', async () => {
      const response = await request(app)
        .post(`/projects/${projectId}/tasks/${taskId}/comments`)
        .send({ message: 'Test Comment' });
      expect(response.status).toBe(201);
      expect(response.body.comment.message).toBe('Test Comment');
    });
  });

  describe('Members', () => {
    it('should add a member', async () => {
      const response = await request(app)
        .post(`/projects/${projectId}/members`)
        .send({ userId: 'user123', role: 'developer' });
      expect(response.status).toBe(201);
      expect(response.body.member.userId).toBe('user123');
    });
  });
});
